@Test public void singleHeaderValue() {
    Map<String, List<String>> headers = new HashMap<String, List<String>>();
    List<String> values = new ArrayList<String>();
    values.add("application/json");
    headers.put("Content-Type", values);
    HttpConnection.Response res = new HttpConnection.Response();
    res.processResponseHeaders(headers);
    assertEquals("application/json", res.header("Content-Type"));
}

@Test public void threeHeaderValuesCombine() {
    Map<String, List<String>> headers = new HashMap<String, List<String>>();
    List<String> values = new ArrayList<String>();
    values.add("gzip");
    values.add("deflate");
    values.add("br");
    headers.put("Accept-Encoding", values);
    HttpConnection.Response res = new HttpConnection.Response();
    res.processResponseHeaders(headers);
    assertEquals("gzip, deflate, br", res.header("Accept-Encoding"));
}

@Test public void emptyHeaderValuesList() {
    Map<String, List<String>> headers = new HashMap<String, List<String>>();
    List<String> values = new ArrayList<String>();
    headers.put("X-Empty-Header", values);
    HttpConnection.Response res = new HttpConnection.Response();
    res.processResponseHeaders(headers);
    assertNull(res.header("X-Empty-Header"));
}
